23	/***********************************************************************
24	 * Check registry for correct fast-path setting (windows only)
25	 **********************************************************************/
26	#ifdef HAVE_ATLBASE_H
27	#    define CHECK_REG_SEND_THRESH
28	#    include <atlbase.h> //CRegKey
29	static void check_registry_for_fast_send_threshold(const size_t mtu)
30	{
31	    static bool warned = false;
32	    if (warned)
33	        return; // only allow one printed warning per process
34	
35	    CRegKey reg_key;
36	    DWORD threshold = 1024; // system default when threshold is not specified
37	    if (reg_key.Open(HKEY_LOCAL_MACHINE,
38	            "System\\CurrentControlSet\\Services\\AFD\\Parameters",
39	            KEY_READ)
40	            != ERROR_SUCCESS
41	        or reg_key.QueryDWORDValue("FastSendDatagramThreshold", threshold)
42	               != ERROR_SUCCESS
43	        or threshold < mtu) {
44	        UHD_LOGGER_WARNING("UDP")
45	            << boost::format(
46	                   "The MTU (%d) is larger than the FastSendDatagramThreshold (%d)!\n"
47	                   "This will negatively affect the transmit performance.\n"
48	                   "See the transport application notes for more detail.\n")
49	                   % mtu % threshold;
50	        warned = true;
51	    }
52	    reg_key.Close();
53	}
54	#endif /*HAVE_ATLBASE_H*/
