131	/***********************************************************************
132	 * Zero Copy UDP implementation with ASIO:
133	 *   This is the portable zero copy implementation for systems
134	 *   where a faster, platform specific solution is not available.
135	 *   However, it is not a true zero copy implementation as each
136	 *   send and recv requires a copy operation to/from userspace.
137	 **********************************************************************/
138	class udp_zero_copy_asio_impl : public udp_zero_copy
139	{
140	public:
141	    typedef std::shared_ptr<udp_zero_copy_asio_impl> sptr;
142	
143	    udp_zero_copy_asio_impl(const std::string& addr,
144	        const std::string& port,
145	        const zero_copy_xport_params& xport_params)
146	        : _recv_frame_size(xport_params.recv_frame_size)
147	        , _num_recv_frames(xport_params.num_recv_frames)
148	        , _send_frame_size(xport_params.send_frame_size)
149	        , _num_send_frames(xport_params.num_send_frames)
150	        , _recv_buffer_pool(buffer_pool::make(
151	              xport_params.num_recv_frames, xport_params.recv_frame_size))
152	        , _send_buffer_pool(buffer_pool::make(
153	              xport_params.num_send_frames, xport_params.send_frame_size))
154	        , _next_recv_buff_index(0)
155	        , _next_send_buff_index(0)
156	    {
157	        UHD_LOGGER_TRACE("UDP")
158	            << boost::format("Creating UDP transport to %s:%s") % addr % port;
159	
160	#ifdef CHECK_REG_SEND_THRESH
161	        check_registry_for_fast_send_threshold(this->get_send_frame_size());
162	#endif /*CHECK_REG_SEND_THRESH*/
163	
164	        _socket  = open_udp_socket(addr, port, _io_context);
165	        _sock_fd = _socket->native_handle();
166	
167	        UHD_LOGGER_TRACE("UDP") << boost::format("Local UDP socket endpoint: %s:%s")
168	                                       % get_local_addr() % get_local_port();
169	
170	        // allocate re-usable managed receive buffers
171	        for (size_t i = 0; i < get_num_recv_frames(); i++) {
172	            _mrb_pool.push_back(std::make_shared<udp_zero_copy_asio_mrb>(
173	                _recv_buffer_pool->at(i), _sock_fd, get_recv_frame_size()));
174	        }
175	
176	        // allocate re-usable managed send buffers
177	        for (size_t i = 0; i < get_num_send_frames(); i++) {
178	            _msb_pool.push_back(std::make_shared<udp_zero_copy_asio_msb>(
179	                _send_buffer_pool->at(i), _sock_fd, get_send_frame_size()));
180	        }
181	    }
182	
183	    size_t resize_send_socket_buffer(size_t num_bytes)
184	    {
185	        return resize_udp_socket_buffer<asio::socket_base::send_buffer_size>(
186	            _socket, num_bytes);
187	    }
188	
189	    size_t resize_recv_socket_buffer(size_t num_bytes)
190	    {
191	        return resize_udp_socket_buffer<asio::socket_base::receive_buffer_size>(
192	            _socket, num_bytes);
193	    }
194	
195	    /*******************************************************************
196	     * Receive implementation:
197	     * Block on the managed buffer's get call and advance the index.
198	     ******************************************************************/
199	    managed_recv_buffer::sptr get_recv_buff(double timeout) override
200	    {
201	        if (_next_recv_buff_index == _num_recv_frames)
202	            _next_recv_buff_index = 0;
203	        return _mrb_pool[_next_recv_buff_index]->get_new(timeout, _next_recv_buff_index);
204	    }
205	
206	    size_t get_num_recv_frames(void) const override
207	    {
208	        return _num_recv_frames;
209	    }
210	    size_t get_recv_frame_size(void) const override
211	    {
212	        return _recv_frame_size;
213	    }
214	
215	    /*******************************************************************
216	     * Send implementation:
217	     * Block on the managed buffer's get call and advance the index.
218	     ******************************************************************/
219	    managed_send_buffer::sptr get_send_buff(double timeout) override
220	    {
221	        if (_next_send_buff_index == _num_send_frames)
222	            _next_send_buff_index = 0;
223	        return _msb_pool[_next_send_buff_index]->get_new(timeout, _next_send_buff_index);
224	    }
225	
226	    size_t get_num_send_frames(void) const override
227	    {
228	        return _num_send_frames;
229	    }
230	    size_t get_send_frame_size(void) const override
231	    {
232	        return _send_frame_size;
233	    }
234	
235	    uint16_t get_local_port(void) const override
236	    {
237	        return _socket->local_endpoint().port();
238	    }
239	
240	    std::string get_local_addr(void) const override
241	    {
242	        return _socket->local_endpoint().address().to_string();
243	    }
244	
245	private:
246	    // memory management -> buffers and fifos
247	    const size_t _recv_frame_size, _num_recv_frames;
248	    const size_t _send_frame_size, _num_send_frames;
249	    buffer_pool::sptr _recv_buffer_pool, _send_buffer_pool;
250	    std::vector<std::shared_ptr<udp_zero_copy_asio_msb>> _msb_pool;
251	    std::vector<std::shared_ptr<udp_zero_copy_asio_mrb>> _mrb_pool;
252	    size_t _next_recv_buff_index, _next_send_buff_index;
253	
254	    // asio guts -> socket and service
255	    asio::io_context _io_context;
256	    socket_sptr _socket;
257	    int _sock_fd;
258	};
259	
260	/***********************************************************************
261	 * UDP zero copy make function
262	 **********************************************************************/
263	udp_zero_copy::sptr udp_zero_copy::make(const std::string& addr,
264	    const std::string& port,
265	    const zero_copy_xport_params& default_buff_args,
266	    udp_zero_copy::buff_params& buff_params_out,
267	    const device_addr_t& hints)
268	{
269	    // Initialize xport_params
270	    zero_copy_xport_params xport_params = default_buff_args;
271	
272	    xport_params.recv_frame_size =
273	        size_t(hints.cast<double>("recv_frame_size", default_buff_args.recv_frame_size));
274	    xport_params.num_recv_frames =
275	        size_t(hints.cast<double>("num_recv_frames", default_buff_args.num_recv_frames));
276	    xport_params.send_frame_size =
277	        size_t(hints.cast<double>("send_frame_size", default_buff_args.send_frame_size));
278	    xport_params.num_send_frames =
279	        size_t(hints.cast<double>("num_send_frames", default_buff_args.num_send_frames));
280	    xport_params.recv_buff_size =
281	        size_t(hints.cast<double>("recv_buff_size", default_buff_args.recv_buff_size));
282	    xport_params.send_buff_size =
283	        size_t(hints.cast<double>("send_buff_size", default_buff_args.send_buff_size));
284	
285	    if (xport_params.num_recv_frames == 0) {
286	        UHD_LOG_TRACE(
287	            "UDP", "Default value for num_recv_frames: " << UDP_DEFAULT_NUM_FRAMES);
288	        xport_params.num_recv_frames = UDP_DEFAULT_NUM_FRAMES;
289	    }
290	    if (xport_params.num_send_frames == 0) {
291	        UHD_LOG_TRACE(
292	            "UDP", "Default value for no num_send_frames: " << UDP_DEFAULT_NUM_FRAMES);
293	        xport_params.num_send_frames = UDP_DEFAULT_NUM_FRAMES;
294	    }
295	    if (xport_params.recv_frame_size == 0) {
296	        UHD_LOG_TRACE("UDP",
297	            "Using default value for  recv_frame_size: " << UDP_DEFAULT_FRAME_SIZE);
298	        xport_params.recv_frame_size = UDP_DEFAULT_FRAME_SIZE;
299	    }
300	    if (xport_params.send_frame_size == 0) {
301	        UHD_LOG_TRACE(
302	            "UDP", "Using default value for send_frame_size, " << UDP_DEFAULT_FRAME_SIZE);
303	        xport_params.send_frame_size = UDP_DEFAULT_FRAME_SIZE;
304	    }
305	
306	    UHD_LOG_TRACE("UDP", "send_frame_size: " << xport_params.send_frame_size);
307	    UHD_LOG_TRACE("UDP", "recv_frame_size: " << xport_params.recv_frame_size);
308	
309	    if (xport_params.recv_buff_size == 0) {
310	        UHD_LOG_TRACE("UDP", "Using default value for recv_buff_size");
311	        xport_params.recv_buff_size = std::max(
312	            UDP_DEFAULT_BUFF_SIZE, xport_params.num_recv_frames * MAX_ETHERNET_MTU);
313	        UHD_LOG_TRACE("UDP",
314	            "Using default value for recv_buff_size" << xport_params.recv_buff_size);
315	    }
316	    if (xport_params.send_buff_size == 0) {
317	        UHD_LOG_TRACE("UDP", "default_buff_args has no send_buff_size");
318	        xport_params.send_buff_size = std::max(
319	            UDP_DEFAULT_BUFF_SIZE, xport_params.num_send_frames * MAX_ETHERNET_MTU);
320	    }
321	
322	#if defined(UHD_PLATFORM_MACOS) || defined(UHD_PLATFORM_BSD)
323	    // limit default buffer size on macos to avoid the warning issued by
324	    // resize_buff_helper
325	    if (not hints.has_key("recv_buff_size")
326	        and xport_params.recv_buff_size > MAX_BUFF_SIZE_ETH_MACOS) {
327	        xport_params.recv_buff_size = MAX_BUFF_SIZE_ETH_MACOS;
328	    }
329	    if (not hints.has_key("send_buff_size")
330	        and xport_params.send_buff_size > MAX_BUFF_SIZE_ETH_MACOS) {
331	        xport_params.send_buff_size = MAX_BUFF_SIZE_ETH_MACOS;
332	    }
333	#endif
334	
335	    udp_zero_copy_asio_impl::sptr udp_trans(
336	        new udp_zero_copy_asio_impl(addr, port, xport_params));
337	
338	    // call the helper to resize send and recv buffers
339	    buff_params_out.recv_buff_size = resize_udp_socket_buffer_with_warning(
340	        [udp_trans](size_t size) { return udp_trans->resize_recv_socket_buffer(size); },
341	        xport_params.recv_buff_size,
342	        "recv");
343	    buff_params_out.send_buff_size = resize_udp_socket_buffer_with_warning(
344	        [udp_trans](size_t size) { return udp_trans->resize_send_socket_buffer(size); },
345	        xport_params.send_buff_size,
346	        "send");
347	
