202	/*!
203	 * Determines a set of values to use for a UDP CHDR link based on defaults and
204	 * any overrides that the user may have provided. In cases where both device
205	 * and stream arguments can be used to override a value, note that the stream
206	 * argument will always take precedence. If no values are requested, we fall
207	 * back to the \p default_link_params.
208	 *
209	 * The \p recv_mtu and \p send_mtu always serve as upper bounds for the
210	 * `recv_frame_size` and `send_frame_size` values.
211	 *
212	 * \param link_type the link type (CTRL, RX, TX) to calculate parameters for
213	 * \param send_mtu the MTU of link for Tx cases
214	 * \param recv_mtu the MTU of link for Rx cases
215	 * \param default_link_params default values to use for the link parameters
216	 * \param device_args device-level argument dictionary for overrides
217	 * \param link_args argument dictionary with stream-level overrides (come from
218	 *        stream params)
219	 * \return Parameters to apply
220	 */
221	inline link_params_t calculate_udp_link_params(
222	    const uhd::transport::link_type_t link_type,
223	    const size_t send_mtu,
224	    const size_t recv_mtu,
225	    const link_params_t& default_link_params,
226	    const uhd::device_addr_t& device_args,
227	    const uhd::device_addr_t& link_args)
228	{
229	    // Apply any device-level overrides to the default values first.
230	    // If the MTU is overridden, it will be capped to the value provided by
231	    // the caller.
232	    const size_t constrained_send_mtu =
233	        std::min(send_mtu, device_args.cast<size_t>("mtu", send_mtu));
234	    const size_t constrained_recv_mtu =
235	        std::min(recv_mtu, device_args.cast<size_t>("mtu", recv_mtu));
236	
237	    // link_params is the return value. First, we merge device_args and
238	    // default_link_params.
239	    link_params_t link_params;
240	    link_params.num_send_frames =
241	        device_args.cast<size_t>("num_send_frames", default_link_params.num_send_frames);
242	    link_params.num_recv_frames =
243	        device_args.cast<size_t>("num_recv_frames", default_link_params.num_recv_frames);
244	    link_params.send_frame_size =
245	        device_args.cast<size_t>("send_frame_size", default_link_params.send_frame_size);
246	    link_params.recv_frame_size =
247	        device_args.cast<size_t>("recv_frame_size", default_link_params.recv_frame_size);
248	    link_params.send_buff_size =
249	        device_args.cast<size_t>("send_buff_size", default_link_params.send_buff_size);
250	    link_params.recv_buff_size =
251	        device_args.cast<size_t>("recv_buff_size", default_link_params.recv_buff_size);
252	
253	    // Now apply stream-level overrides based on the link type. Here, we consider
254	    // the values in link_args.
255	    if (link_type == link_type_t::CTRL) {
256	        // Control links typically do not allow the number of frames to be
257	        // configured.
258	        // Keep the default_link_params value if it is higher to handle
259	        // high speed DPDK links
260	        link_params.num_recv_frames =
261	            std::max(uhd::rfnoc::CMD_FIFO_SIZE / uhd::rfnoc::MAX_CMD_PKT_SIZE,
262	                link_params.num_recv_frames);
263	    } else if (link_type == link_type_t::TX_DATA) {
264	        // Note that the send frame size will be capped to the Tx MTU.
265	        link_params.send_frame_size = std::min(
266	            link_args.cast<size_t>("send_frame_size", link_params.send_frame_size),
267	            constrained_send_mtu);
268	        link_params.num_send_frames =
269	            link_args.cast<size_t>("num_send_frames", link_params.num_send_frames);
270	        link_params.send_buff_size =
271	            link_args.cast<size_t>("send_buff_size", link_params.send_buff_size);
272	    } else if (link_type == link_type_t::RX_DATA) {
273	        // Note that the receive frame size will be capped to the Rx MTU.
274	        link_params.recv_frame_size = std::min(
275	            link_args.cast<size_t>("recv_frame_size", link_params.recv_frame_size),
276	            constrained_recv_mtu);
277	        link_params.num_recv_frames =
278	            link_args.cast<size_t>("num_recv_frames", link_params.num_recv_frames);
279	        link_params.recv_buff_size =
280	            link_args.cast<size_t>("recv_buff_size", link_params.recv_buff_size);
281	    }
282	
283	    // Finally, we apply any other constraints based on the platform.
284	#if defined(UHD_PLATFORM_MACOS) || defined(UHD_PLATFORM_BSD)
285	    // limit buffer size on OSX to avoid the warning issued by
286	    // resize_buff_helper
287	    if (link_params.recv_buff_size > MAX_BUFF_SIZE_ETH_MACOS) {
288	        link_params.recv_buff_size = MAX_BUFF_SIZE_ETH_MACOS;
289	    }
290	    if (link_params.send_buff_size > MAX_BUFF_SIZE_ETH_MACOS) {
291	        link_params.send_buff_size = MAX_BUFF_SIZE_ETH_MACOS;
292	    }
293	#endif
294	
295	    return link_params;
296	}
